questions = [
{"id":"3481","tipo":"multipla","disciplina":"Matemática","tema":"Funções","subtema":"Zeros da função quadrática","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A função f(x) = x² - 9 tem zeros em:","alternativa_a":"x = 3 e x = -3","alternativa_b":"x = 9 e x = -9","alternativa_c":"x = 3 apenas","alternativa_d":"x = 0","alternativa_e":"Não possui zeros reais","resposta_correta":"a","explicacao":"x² - 9 = 0 → x² = 9 → x = ±3. Diferença de quadrados: (x-3)(x+3)=0.","resposta":""},
{"id":"3482","tipo":"multipla","disciplina":"Física","tema":"Eletricidade","subtema":"Energia elétrica","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"Um ferro de passar de 1000 W usado por 2 horas consome quantos kWh?","alternativa_a":"2 kWh","alternativa_b":"0,5 kWh","alternativa_c":"20 kWh","alternativa_d":"200 kWh","alternativa_e":"0,2 kWh","resposta_correta":"a","explicacao":"E = P×t = 1 kW × 2 h = 2 kWh.","resposta":""},
{"id":"3483","tipo":"multipla","disciplina":"Química","tema":"Ligações Químicas","subtema":"Ligação iônica","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"A ligação iônica se forma entre:","alternativa_a":"Metal e ametal — por transferência de elétrons","alternativa_b":"Dois ametais — por compartilhamento de elétrons","alternativa_c":"Dois metais — por elétrons livres","alternativa_d":"Metal e metal — por transferência de nêutrons","alternativa_e":"Qualquer par de átomos com o mesmo elemento","resposta_correta":"a","explicacao":"Iônica: metal (baixa eletronegatividade, doa e⁻) + ametal (alta eletronegatividade, recebe e⁻) → cátion + ânion → atração eletrostática. Ex.: NaCl.","resposta":""},
{"id":"3484","tipo":"multipla","disciplina":"Biologia","tema":"Imunologia","subtema":"Anticorpos","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Os anticorpos (imunoglobulinas) são produzidos por:","alternativa_a":"Plasmócitos (linfócitos B diferenciados)","alternativa_b":"Linfócitos T citotóxicos","alternativa_c":"Macrófagos","alternativa_d":"Neutrófilos","alternativa_e":"Células NK","resposta_correta":"a","explicacao":"Linfócito B ativado por antígeno → diferencia-se em plasmócito → secreta anticorpos específicos para aquele antígeno. Anticorpos: IgG, IgM, IgA, IgE, IgD.","resposta":""},
{"id":"3485","tipo":"multipla","disciplina":"História","tema":"História Geral","subtema":"Idade Média","dificuldide":"Médio","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"O sistema feudal na Europa medieval caracterizou-se pelo(a):","alternativa_a":"Relação de suserania e vassalagem baseada na posse de terras e serviços militares","alternativa_b":"Economia monetária e comércio internacional desenvolvido","alternativa_c":"Forte poder centralizado em um Estado nacional","alternativa_d":"Separação rígida entre Igreja e Estado","alternativa_e":"Igualdade jurídica entre todos os membros da sociedade","resposta_correta":"a","explicacao":"Feudalismo: suserano cede feudo (terra) ao vassalo em troca de lealdade e serviço militar. Base agrária, descentralização política, servidão. Tríade: nobreza, clero, servos.","resposta":""},
{"id":"3486","tipo":"multipla","disciplina":"Geografia","tema":"Geopolítica","subtema":"ONU e organismos internacionais","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O Conselho de Segurança da ONU tem poder de veto exercido por:","alternativa_a":"Os 5 membros permanentes: EUA, Rússia, China, Reino Unido e França","alternativa_b":"Todos os 193 países membros","alternativa_c":"Os 10 membros rotativos eleitos","alternativa_d":"Apenas os países com armas nucleares","alternativa_e":"O Secretário-Geral da ONU","resposta_correta":"a","explicacao":"Conselho de Segurança: 5 membros permanentes (P5) com direito a veto + 10 membros não-permanentes rotativos (2 anos). O veto de qualquer P5 bloqueia qualquer resolução — crítica frequente ao funcionamento da ONU.","resposta":""},
{"id":"3487","tipo":"multipla","disciplina":"Português","tema":"Gramática","subtema":"Vozes verbais","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"'O ladrão foi preso pela polícia.' Esta frase está na voz:","alternativa_a":"Passiva analítica","alternativa_b":"Ativa","alternativa_c":"Reflexiva","alternativa_d":"Passiva sintética","alternativa_e":"Recíproca","resposta_correta":"a","explicacao":"Voz passiva analítica: verbo ser/estar/ficar + particípio. O sujeito (ladrão) sofre a ação. Agente da passiva (pela polícia). Voz ativa seria: 'A polícia prendeu o ladrão.'","resposta":""},
{"id":"3488","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Oriental","subtema":"Confucionismo","dificuldide":"Médio","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"O confucionismo, fundamento filosófico da cultura chinesa, enfatiza:","alternativa_a":"A harmonia social, a piedade filial e a moralidade do governante","alternativa_b":"A libertação do desejo como caminho para o nirvana","alternativa_c":"A resistência ao Estado e a valorização do indivíduo","alternativa_d":"A acumulação de riqueza como virtude suprema","alternativa_e":"O relativismo moral e a ausência de hierarquia","resposta_correta":"a","explicacao":"Confúcio (551-479 a.C.): ética social baseada em relações hierárquicas harmoniosas (governante-súdito, pai-filho, marido-mulher, irmão mais velho-mais novo, amigo-amigo). Virtude central: ren (benevolência/humanidade). Governante virtuoso → sociedade harmoniosa.","resposta":""},
{"id":"3489","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia do Esporte","subtema":"Esporte e sociedade","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"Do ponto de vista sociológico, o esporte é considerado um fato social porque:","alternativa_a":"Reflete e reproduz valores, tensões e desigualdades da sociedade","alternativa_b":"É uma atividade puramente individual sem influência social","alternativa_c":"Está completamente separado da política e da economia","alternativa_d":"Só pode ser compreendido pelos praticantes","alternativa_e":"Não tem relação com identidade nacional ou cultural","resposta_correta":"a","explicacao":"O esporte espelha a sociedade: competição (capitalismo), nacionalismo (Copa do Mundo), racismo no futebol, comercialização, desigualdade de gênero, doping como pressão por performance. Elias e Dunning: o esporte como espaço de 'excitação controlada'.","resposta":""},
{"id":"3490","tipo":"multipla","disciplina":"Literatura","tema":"Poesia Contemporânea","subtema":"Adélia Prado","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"A poesia de Adélia Prado é marcada pela:","alternativa_a":"Fusão entre o cotidiano doméstico e o sagrado/místico","alternativa_b":"Linguagem hermética e abstrata sem referências concretas","alternativa_c":"Crítica política explícita ao regime ditatorial","alternativa_d":"Valorização exclusiva da natureza amazônica","alternativa_e":"Uso do romance histórico como forma poética","resposta_correta":"a","explicacao":"Adélia Prado (n. 1935, MG): poesia que eleva o cotidiano doméstico (cozinha, família, corpo feminino) à dimensão sagrada. Influência da fé católica e de Carlos Drummond. 'Bagagem' (1976): revelação poética tardia (40 anos). Frase célebre: 'Não sou feminista, sou poeta.'","resposta":""},
{"id":"3491","tipo":"multipla","disciplina":"Matemática","tema":"Trigonometria","subtema":"Gráficos das funções trigonométricas","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A função y = sen(x) tem período igual a:","alternativa_a":"2π","alternativa_b":"π","alternativa_c":"π/2","alternativa_d":"4π","alternativa_e":"1","resposta_correta":"a","explicacao":"A função seno completa um ciclo completo a cada 2π radianos (360°). Período = 2π ≈ 6,28 rad.","resposta":""},
{"id":"3492","tipo":"multipla","disciplina":"Física","tema":"Física Nuclear","subtema":"Fissão e fusão nuclear","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"A energia nuclear das usinas elétricas provém de:","alternativa_a":"Fissão nuclear — divisão de núcleos pesados (urânio, plutônio)","alternativa_b":"Fusão nuclear — união de núcleos leves","alternativa_c":"Radioatividade natural do urânio","alternativa_d":"Reações químicas de oxidação do urânio","alternativa_e":"Fissão de núcleos de hidrogênio","resposta_correta":"a","explicacao":"Usinas nucleares: fissão de U-235 ou Pu-239 libera energia (E=mc²) → aquece água → vapor → turbina → gerador. Fusão (sol, bomba H) ainda não é viável para geração comercial.","resposta":""},
{"id":"3493","tipo":"multipla","disciplina":"Química","tema":"Substâncias","subtema":"Misturas homogêneas e heterogêneas","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"Uma mistura de água e sal dissolvido é classificada como:","alternativa_a":"Mistura homogênea (solução)","alternativa_b":"Mistura heterogênea","alternativa_c":"Substância pura","alternativa_d":"Elemento químico","alternativa_e":"Composto iônico puro","resposta_correta":"a","explicacao":"Sal dissolvido em água: solução aquosa (mistura homogênea — fase única, não se distinguem os componentes a olho nu). Mistura heterogênea: distinguem-se as fases (areia+água).","resposta":""},
{"id":"3494","tipo":"multipla","disciplina":"Biologia","tema":"Fisiologia Humana","subtema":"Sistema digestório","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"A digestão química dos carboidratos começa em qual estrutura?","alternativa_a":"Boca — ação da amilase salivar","alternativa_b":"Estômago — ação do ácido clorídrico","alternativa_c":"Intestino delgado — ação do pâncreas","alternativa_d":"Esôfago — ação do peristaltismo","alternativa_e":"Intestino grosso — ação das bactérias","resposta_correta":"a","explicacao":"Amilase salivar (ptialina): hidrolisa amido em maltose na boca. No estômago, a digestão de carboidratos para pois o ambiente ácido inativa a amilase. Continua no intestino (amilase pancreática).","resposta":""},
{"id":"3495","tipo":"multipla","disciplina":"História","tema":"História do Brasil","subtema":"Inconfidência Mineira","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"A Inconfidência Mineira (1789) foi um movimento de:","alternativa_a":"Independência contra o domínio português, inspirado no iluminismo e na Revolução Americana","alternativa_b":"Revolta dos escravizados contra seus senhores","alternativa_c":"Movimento operário contra a exploração industrial","alternativa_d":"Rebelião de indígenas contra os jesuítas","alternativa_e":"Golpe militar para instaurar uma monarquia constitucional","resposta_correta":"a","explicacao":"Inconfidência Mineira: conspiração de elites letradas de MG (Tiradentes, Tomás Antônio Gonzaga, etc.) para independência de Portugal, inspirados pelo iluminismo e pela Revolução Americana (1776). Delatada antes de executada. Tiradentes: único punido com morte.","resposta":""},
{"id":"3496","tipo":"multipla","disciplina":"Geografia","tema":"Vegetação","subtema":"Mata Atlântica","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A Mata Atlântica, um dos biomas mais ameaçados do mundo, hoje:","alternativa_a":"Cobre apenas ~12% de sua área original","alternativa_b":"Está completamente preservada nas regiões Sul e Sudeste","alternativa_c":"Ocupa mais área que o Cerrado atualmente","alternativa_d":"Nunca foi legalmente protegida no Brasil","alternativa_e":"Não abriga espécies endêmicas significativas","resposta_correta":"a","explicacao":"Mata Atlântica: originalmente cobria ~15% do território brasileiro (1,3 mi km²). Hoje restam ~12% em fragmentos (principalmente no RJ, SP, ES, SC). Abriga mais de 8.000 espécies endêmicas de plantas. Lei 11.428/2006 protege os remanescentes.","resposta":""},
{"id":"3497","tipo":"multipla","disciplina":"Filosofia","tema":"Epistemologia","subtema":"Ceticismo","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"O ceticismo filosófico, em sua forma mais radical, defende que:","alternativa_a":"O conhecimento certo é impossível ou muito limitado","alternativa_b":"O conhecimento é sempre possível pela razão pura","alternativa_c":"Apenas os sentidos podem fornecer conhecimento confiável","alternativa_d":"A ciência moderna garante certeza absoluta","alternativa_e":"A fé religiosa é o único caminho para a verdade","resposta_correta":"a","explicacao":"Ceticismo: doutrina que questiona a possibilidade do conhecimento certo. Pirro (ceticismo antigo): suspensão do julgamento (epoché). Hume: ceticismo moderado (impressões nos dão conhecimento provável, não certo). Descartes usou a dúvida cética como método, mas para encontrar certezas.","resposta":""},
{"id":"3498","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia Econômica","subtema":"Capitalismo — origens","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O capitalismo como sistema econômico tem como características fundamentais:","alternativa_a":"Propriedade privada dos meios de produção, trabalho assalariado e produção para o mercado","alternativa_b":"Propriedade coletiva dos meios de produção e planejamento central","alternativa_c":"Ausência de moeda e troca direta entre produtores","alternativa_d":"Produção exclusivamente para subsistência sem excedente","alternativa_e":"Controle do Estado sobre todos os preços e salários","resposta_correta":"a","explicacao":"Capitalismo: (1) Meios de produção privados (burguesia); (2) Trabalhadores livres que vendem força de trabalho (proletariado assalariado); (3) Produção mercantil — bens produzidos para venda no mercado; (4) Acumulação de capital como fim. Difere do feudalismo (servidão) e do socialismo (propriedade coletiva).","resposta":""},
{"id":"3499","tipo":"multipla","disciplina":"Literatura","tema":"Poesia Brasileira","subtema":"Vinicius de Moraes","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"O soneto 'De Tudo Ao Meu Amor' de Vinicius de Moraes é conhecido pela célebre frase:","alternativa_a":"'Que seja eterno enquanto dure'","alternativa_b":"'No meio do caminho tinha uma pedra'","alternativa_c":"'Sou um apanhador de desperdícios'","alternativa_d":"'Tenho em mim este peso da raça'","alternativa_e":"'Morte e vida Severina'","resposta_correta":"a","explicacao":"'De Tudo ao Meu Amor' (Vinicius de Moraes): soneto que paradoxalmente defende o amor efêmero — 'Que não seja imortal, posto que é chama / Mas que seja infinito enquanto dure.' A frase 'que seja eterno enquanto dure' é paráfrase popular do poema.","resposta":""},
{"id":"3500","tipo":"multipla","disciplina":"Matemática","tema":"Álgebra","subtema":"Fatoração","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Qual é a fatoração completa de x² - 6x + 9?","alternativa_a":"(x - 3)²","alternativa_b":"(x + 3)²","alternativa_c":"(x - 3)(x + 3)","alternativa_d":"(x - 9)(x + 1)","alternativa_e":"x(x - 6) + 9","resposta_correta":"a","explicacao":"Trinômio quadrado perfeito: a² - 2ab + b² = (a-b)². x² - 6x + 9 = x² - 2(3)x + 3² = (x-3)².","resposta":""},
{"id":"4371","tipo":"dissertativa","disciplina":"Matemática","tema":"Análise Combinatória","subtema":"Permutações com repetição","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Quantos anagramas podem ser formados com as letras da palavra BANANA?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"BANANA: 6 letras com repetição — B(1), A(3), N(2). Permutação com repetição: P = 6!/(1!×3!×2!) = 720/(1×6×2) = 720/12 = 60 anagramas.","resposta":"60 anagramas — P = 6!/(1!×3!×2!) = 60"},
{"id":"4372","tipo":"dissertativa","disciplina":"Física","tema":"Mecânica","subtema":"Conservação do momento linear","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Dois carrinhos, A (2 kg, 4 m/s) e B (3 kg, parado), colidem e ficam grudados. Qual a velocidade final?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Conservação do momento (colisão perfeitamente inelástica): p_antes = p_depois. m_A×v_A + m_B×v_B = (m_A+m_B)×v_f. 2×4 + 3×0 = 5×v_f. 8 = 5×v_f. v_f = 8/5 = 1,6 m/s na mesma direção e sentido do carrinho A.","resposta":"v_f = 1,6 m/s"},
{"id":"4373","tipo":"dissertativa","disciplina":"Química","tema":"Bioquímica","subtema":"Fotossíntese — equação global","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"Escreva a equação global da fotossíntese e identifique as moléculas que entram e saem. Onde cada fase ocorre?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"6CO₂ + 6H₂O + energia luminosa → C₆H₁₂O₆ + 6O₂. Entram: CO₂ (pelos estômatos) e H₂O (pelas raízes). Saem: glicose (usada para energia e estrutura) e O₂ (subproduto liberado pelos estômatos). Fase luminosa: tilacoides (fotólise da água, produção de ATP e NADPH, liberação de O₂). Fase escura (Ciclo de Calvin): estroma (fixação de CO₂, síntese de glicose usando ATP e NADPH).","resposta":"6CO₂ + 6H₂O → C₆H₁₂O₆ + 6O₂. Fase luminosa: tilacoides. Ciclo de Calvin: estroma."},
{"id":"4374","tipo":"dissertativa","disciplina":"Biologia","tema":"Zoologia","subtema":"Mamíferos — características","dificuldade":"Fácil","fonte":"Vestibular","ano":"2023","enunciado":"Quais são as características que definem os mamíferos? Como se diferenciam de outros vertebrados?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Características dos mamíferos: (1) Glândulas mamárias — amamentam os filhotes; (2) Pelos/cabelos (queratina) — em alguma fase da vida; (3) Homeotérmicos (sangue quente) — regulam temperatura interna; (4) Diafragma — músculo respiratório exclusivo; (5) Mandíbula com um único osso (dentário); (6) 3 ossículos no ouvido médio (martelo, bigorna, estribo). Comparação: Aves: também homeotérmicas, mas têm penas e bico. Répteis: ectotérmicos (sangue frio). Anfíbios: ectotérmicos, pele úmida. Peixes: brânquias, ectotérmicos. Monotremados (ornitorrinco, equidna) são mamíferos ovíparos — exceção.","resposta":"Mamíferos: glândulas mamárias, pelos, homeotérmicos, diafragma. Diferenciam-se de aves (penas), répteis (ectotérmicos) e anfíbios (pele úmida)."},
{"id":"4375","tipo":"dissertativa","disciplina":"História","tema":"História do Brasil","subtema":"Modernização conservadora — JK","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O governo Juscelino Kubitschek (1956-1961) ficou marcado pela modernização do Brasil. Explique seu projeto '50 anos em 5' e seus desdobramentos.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"JK: Plano de Metas (1956) — 31 metas setoriais em energia, transporte, indústria de base e alimentos + 1 meta síntese: construção de Brasília. '50 anos em 5': slogan que refletia a ambição de industrializar e modernizar o Brasil em velocidade acelerada. Resultados: instalação da indústria automobilística (Volkswagen, Ford, GM), hidrelétricas, rodovias, construção de Brasília (inaugurada 1960). Custos: inflação acelerada, dívida externa crescente, dependência de capital externo, concentração de renda. Base do 'desenvolvimentismo': Estado como indutor do crescimento com abertura ao capital estrangeiro.","resposta":"Plano de Metas: 31 metas + Brasília. Industrialização acelerada (automóveis, energia). Custo: inflação, dívida externa, concentração de renda."},
{"id":"4376","tipo":"dissertativa","disciplina":"Geografia","tema":"Transportes","subtema":"Matriz de transportes brasileira","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"A matriz de transportes brasileira é marcada pela predominância do transporte rodoviário. Quais são as consequências dessa dependência e como poderia ser diversificada?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Brasil: ~65% do transporte de cargas e ~95% de passageiros é rodoviário (ANTT). Causas históricas: Plano de Metas JK priorizou rodovias + indústria automotiva; ferrovias privatizadas/abandonadas; precário investimento em hidrovias. Consequências: alto consumo de combustível fóssil (CO₂), custos elevados do frete (Custo Brasil), desgaste rápido de rodovias, acidentes, gargalos logísticos (Br-163, corredor de soja). Diversificação: (1) Ferroviário (trem de alta velocidade SP-RJ, trens de carga); (2) Hidrovias (Tietê-Paraná, Tapajós — polêmica ambiental); (3) Cabotagem (navegação costeira); (4) Multimodalidade integrada.","resposta":"Matriz rodoviária (65% cargas): alto custo, poluição, desgaste. Diversificação: ferrovias, hidrovias, cabotagem, multimodalidade."},
{"id":"4377","tipo":"dissertativa","disciplina":"Português","tema":"Literatura","subtema":"Drummond — 'A Máquina do Mundo'","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"Em 'A Máquina do Mundo' de Drummond, o poeta recusa a revelação oferecida pela máquina. O que esse gesto significa?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"'A Máquina do Mundo' (1951, 'Claro Enigma'): caminhando no fim do dia em Minas, a 'máquina do mundo' se abre para o poeta, oferecendo-lhe o segredo do universo — toda a verdade. O poeta recusa: 'e a toda visão superior, / ao ser e ao não-ser, / preferi o caminhar, a tarde, a luz.' O gesto simboliza: (1) Humildade existencial — a verdade absoluta não cabe no humano; (2) Valorização da experiência concreta sobre a metafísica; (3) Melancolia moderna — o poeta sabe que a revelação existe mas não a deseja mais; (4) Diálogo com Dante (estrutura, vocabulário arcaizante) e com a tradição épica que ele relê criticamente. Poema síntese do pessimismo e sabedoria da maturidade de Drummond.","resposta":"Recusa da revelação absoluta = valorização da experiência concreta, humildade existencial, melancolia moderna. A verdade total é insuportável — prefere-se o caminhar."},
{"id":"4378","tipo":"dissertativa","disciplina":"Filosofia","tema":"Filosofia da Ação","subtema":"Liberdade e responsabilidade","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Para o existencialismo sartriano, se o ser humano é 'condenado a ser livre', como isso implica responsabilidade total?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Sartre: sem Deus, sem natureza humana prévia, o ser humano cria a si mesmo por suas escolhas. A liberdade é radical e inevitável — mesmo não escolher é uma escolha. 'Condenado': não pedimos para nascer livres, mas não podemos escapar da liberdade. Consequência: responsabilidade total — não posso culpar Deus, genes, sociedade ou passado pelas minhas escolhas. 'Má-fé' (mauvaise foi): negação da própria liberdade, fingir que se é determinado (o garçom que 'é' garçom, o racista que 'não pode' ser diferente). Angústia: vertigem da liberdade — a consciência de que poderíamos ter escolhido de outra forma. Comprometimento (engagement): devo me engajar politicamente pois não escolher também é escolha.","resposta":"Liberdade radical = responsabilidade total: não posso culpar ninguém pelas minhas escolhas. Má-fé = negar a própria liberdade. Angústia = vertigem da escolha irrecusável."},
{"id":"4379","tipo":"dissertativa","disciplina":"Sociologia","tema":"Trabalho","subtema":"Automação e o futuro do trabalho","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Como a automação e a inteligência artificial estão transformando o mercado de trabalho? Quais são os cenários possíveis?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Automação (robôs industriais) e IA (aprendizado de máquina) substituem funções repetitivas e cognitivas de rotina. Empregos em risco: operadores de caixa, motoristas (veículos autônomos), contadores, analistas de dados básicos, operários de linha de montagem. Oxford (Frey & Osborne, 2013): 47% dos empregos nos EUA em risco em 20 anos. Cenários: (1) Pessimista — desemprego estrutural em massa, crescimento da desigualdade; (2) Otimista — criação de novos empregos (programadores de IA, engenheiros de robótica, cuidadores) como nas revoluções anteriores; (3) Regulatório — imposto sobre robôs, renda básica universal (RBU), redução da jornada de trabalho. O debate envolve educação (STEM), requalificação e proteção social.","resposta":"Automação substitui empregos repetitivos. Cenários: desemprego estrutural vs. criação de novos empregos. Soluções propostas: renda básica universal, requalificação, imposto sobre robôs."},
{"id":"4380","tipo":"dissertativa","disciplina":"Literatura","tema":"Literatura Angolana","subtema":"Agostinho Neto","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Agostinho Neto foi presidente de Angola e poeta. Como sua poesia dialoga com o colonialismo e a luta pela independência?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Agostinho Neto (1922-1979): líder do MPLA e primeiro presidente de Angola (independência 1975). Sua poesia (coletânea 'Sagrada Esperança', 1974) é intimamente ligada à luta anticolonial contra Portugal. Características: poesia de denúncia da opressão colonial (trabalho forçado, exploração, racismo), esperança na libertação, afirmação da identidade africana (negritude), língua portuguesa ressignificada como arma de resistência. 'Adeus à Hora da Largada': poema mais famoso, de partida para a luta. Sua obra situa-se no contexto do Pan-africanismo e da literatura de combate das colônias portuguesas (Amílcar Cabral, Noémia de Sousa). Ponte entre estética literária e projeto político de libertação nacional.","resposta":"Poesia de denúncia colonial e afirmação da identidade africana. 'Sagrada Esperança': resistência, negritude, português como arma de libertação — poeta-presidente de Angola."},
]

